const users6h = $('Fetch New Users (6h)').first().json;
const users24h = $('Fetch Users at 24h').first().json;
const users48h = $('Fetch Users at 48h').first().json;
const users72h = $('Fetch Users at 72h').first().json;

const allUsers = [];

const addUsers = (data, stage) => {
  const list = Array.isArray(data) ? data : (data.users || []);
  list.forEach(u => allUsers.push({ ...u, stage }));
};

addUsers(users6h, 'welcome');
addUsers(users24h, 'signals');
addUsers(users48h, 'accuracy');
addUsers(users72h, 'referral');

if (allUsers.length === 0) {
  return [{ json: { skip: true, message: 'No onboarding users at this time' } }];
}

return allUsers.map(user => ({
  json: {
    skip: false,
    userId: user.telegram_id || user.chat_id || user.id,
    username: user.username || user.first_name || 'there',
    stage: user.stage
  }
}));

const { stage, username } = $json;

let stageInstructions = '';

switch (stage) {
  case 'welcome':
    stageInstructions = `This user JUST joined (within the last 6 hours). Write an enthusiastic welcome message.
- Introduce BTC Seer briefly (AI-powered Bitcoin predictions)
- Tell them to try /predict as their first command
- Mention they have a free Premium trial active
- Keep it warm and short (under 600 chars)
- Make them feel like they made a great decision joining`;
    break;

  case 'signals':
    stageInstructions = `This user has been here 24 hours. Time to introduce trading signals.
- Ask how their first day went
- Introduce the /signal command for real-time trading signals
- Briefly explain what signals include (direction, confidence, timeframe)
- Encourage them to check the next signal
- Keep it under 600 chars`;
    break;

  case 'accuracy':
    stageInstructions = `This user has been here 48 hours. Show them the track record.
- Acknowledge they've been exploring for 2 days
- Introduce /accuracy to see the platform's prediction track record
- Emphasize transparency — we show wins AND misses
- This builds trust and differentiates from scam bots
- Keep it under 600 chars`;
    break;

  case 'referral':
    stageInstructions = `This user has been here 72 hours. Time for the referral play.
- They've had 3 days to see value — now invite them to share
- Introduce /referral command
- Highlight the reward: BOTH referrer and friend get +7 days Premium
- Make sharing feel natural, not spammy
- Keep it under 600 chars`;
    break;
}

const prompt = `Write a personalized Telegram DM for user "${username}" as part of the onboarding sequence.

${stageInstructions}

Rules:
- Use HTML formatting (<b>, <i>, <code>) — NOT Markdown
- Make it conversational and personal
- Never give financial advice
- Vary your opening — don't always start the same way`;

return [{ json: { prompt, userId: $json.userId, stage } }];

const response = $input.first().json;
const stage = $('Build Claude Prompt').first().json.stage;
let text = '';

if (response.content && response.content.length > 0) {
  text = response.content[0].text;
} else {
  const fallbacks = {
    welcome: '<b>Welcome to BTC Seer!</b>\n\nTry /predict to get your first AI-powered Bitcoin prediction!',
    signals: 'Try /signal to receive real-time trading signals from our AI.',
    accuracy: 'Curious about our track record? Try /accuracy to see our transparent results.',
    referral: 'Love BTC Seer? Use /referral to share with friends — you both get +7 days Premium!'
  };
  text = fallbacks[stage] || fallbacks.welcome;
}

return [{ json: { text, userId: $('Build Claude Prompt').first().json.userId } }];

const result = $input.first().json;
const userId = $('Extract Message Text').first().json.userId;
const success = result.ok === true;

console.log(`[Onboarding] Sent to user ${userId}: ${success ? 'OK' : 'FAILED'}`);

return [{ json: { userId, success, timestamp: new Date().toISOString() } }];
